    "file": "internal/terraform/context_apply.go",
    "line": 153,
    "severity": "critical",
    "description": "The import hook loop calls h.PreApplyImport and h.PostApplyImport but discards both the HookAction return value and the error return value. When Terraform is gracefully shutting down, the stopHook's implementations of these methods return (HookActionHalt, error), but since the return values are ignored, the apply continues instead of halting. Any error returned by a hook is also silently dropped. Every other hook dispatch in the codebase checks these return values (see BuiltinEvalContext.Hook in eval_context_builtin.go). This means a graceful stop signal fired during the import notification phase is not respected, and hook errors are lost.",
    "fix_patch": "--- a/internal/terraform/context_apply.go
+++ b/internal/terraform/context_apply.go
@@ -150,8 +150,12 @@ func (c *Context) ApplyAndEval(plan *plans.Plan, config *configs.Config, opts *A
 			for _, h := range c.hooks {
 				// In future, we may need to call PostApplyImport separately elsewhere in the apply
 				// operation. For now, though, we'll call Pre and Post hooks together.
-				h.PreApplyImport(hookResourceID, *rc.Importing)
-				h.PostApplyImport(hookResourceID, *rc.Importing)
+				if _, err := h.PreApplyImport(hookResourceID, *rc.Importing); err != nil {
+					diags = diags.Append(err)
+				}
+				if _, err := h.PostApplyImport(hookResourceID, *rc.Importing); err != nil {
+					diags = diags.Append(err)
+				}
 			}
 		}
 	}
"
